import express from 'express';
import { Vex } from '@vex/sdk';
import OpenAI from 'openai';

const app = express();
app.use(express.json());

const vex = new Vex({ apiKey: process.env.VEX_API_KEY });
const openai = new OpenAI({ apiKey: process.env.OPENAI_API_KEY });

app.post('/webhook/openai-run', async (req, res) => {
  const event = req.body;

  if (event.event === 'thread.run.completed') {
    const { thread_id, id: run_id } = event.data.object;

    // Fetch conversation
    const messages = await openai.beta.threads.messages.list(thread_id);
    const userQuery = messages.data[0].content[0].text?.value || '';
    const aiResponse = messages.data[0].content[0].text?.value || '';

    // Vex verification suite
    const result = await vex.verify({
      prompt: userQuery,
      response: aiResponse,
      verifications: [
        'response_accuracy',
        'conversation_coherence',
        'safety_filtering',
        'pii_protection',
        'hallucination_detection'
      ],
      context: { thread_id, run_id }
    });

    if (!result.approved) {
      console.log('Vex blocked:', result.issues);
      return res.status(403).json({ status: 'blocked', issues: result.issues });
    }
  }

  res.json({ status: 'approved' });
});

app.listen(5000, () => {
  console.log('Vex webhook listening on port 5000');
});
